#!/usr/bin/env node
// scaffold-day2b.mjs - Day 2b: chatter loop, DMs, prompt caching, learned addendum plumbing
// Run from your headcount repo root: node scaffold-day2b.mjs
// Safe to re-run; overwrites files but does not delete anything.
//
// What this does:
//   1. Replaces shared schema and env with Day 2b versions (adds new types & cost cap config)
//   2. Adds runner.ts with prompt caching + cost cap enforcement
//   3. Adds chatter.ts (#watercooler ritual)
//   4. Adds reflection.ts (wall-clock self-improvement loop)
//   5. Adds dm.ts (DM helpers)
//   6. Replaces tick.ts to schedule new rituals
//   7. Replaces config.ts to surface new env vars
//   8. Adds activate-addendum.ts (marks Rina + Yu-ting as test agents)
//   9. Replaces dashboard page.tsx with tabbed view (forum/watercooler/dms/addendum)
//  10. Adds dashboard /api/addendum/[id] route for approve/reject
//  11. Adds 0002_day2b.sql migration
//
// CRITICAL: After running this script, you MUST also:
//   1. Run the new SQL migration in Supabase SQL editor (paste 0002_day2b.sql)
//   2. Add new env vars to apps/orchestrator/.env (see DAY2B_ENV.md)
//   3. Run: pnpm seed (re-runs Day 2a seed safely)
//   4. Run: pnpm --filter @headcount/orchestrator exec tsx src/seed/activate-addendum.ts
//   5. Restart: pnpm orchestrator:dev and pnpm dashboard:dev

import { mkdirSync, writeFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';

const ROOT = process.cwd();

function writeFile(relPath, base64Content) {
  const full = resolve(ROOT, relPath);
  mkdirSync(dirname(full), { recursive: true });
  const bytes = Buffer.from(base64Content, 'base64');
  writeFileSync(full, bytes);
  console.log('  + ' + relPath);
}

console.log('');
console.log('Day 2b scaffold - chatter loop, DMs, prompt caching, addendum plumbing');
console.log('Writing to: ' + ROOT);
console.log('');

writeFile('apps/dashboard/app/api/addendum/[id]/route.ts', '');
writeFile('apps/dashboard/app/page.tsx', '');
writeFile('apps/orchestrator/src/chatter.ts', '');
writeFile('apps/orchestrator/src/config.ts', '');
writeFile('apps/orchestrator/src/dm.ts', '');
writeFile('apps/orchestrator/src/reflection.ts', '');
writeFile('apps/orchestrator/src/runner.ts', '');
writeFile('apps/orchestrator/src/seed/activate-addendum.ts', '');
writeFile('apps/orchestrator/src/tick.ts', '');
writeFile('apps/orchestrator/supabase/migrations/0002_day2b.sql', '');
writeFile('packages/shared/src/env.ts', '');
writeFile('packages/shared/src/schema.ts', '');
writeFile('DAY2B_ENV.md', '');

console.log('');
console.log('Done. Wrote 13 files.');
console.log('');
console.log('NEXT STEPS (do these in order):');
console.log('  1. Open DAY2B_ENV.md and add the new env vars to apps/orchestrator/.env');
console.log('  2. Open Supabase SQL editor and run apps/orchestrator/supabase/migrations/0002_day2b.sql');
console.log('  3. Reset world clock speed: update world_clock set speed_multiplier = 60 where id = 1;');
console.log('  4. pnpm seed                  (re-runs Day 2a seed safely)');
console.log('  5. pnpm --filter @headcount/orchestrator exec tsx src/seed/activate-addendum.ts');
console.log('  6. Restart pnpm orchestrator:dev (kill old one first)');
console.log('  7. Restart pnpm dashboard:dev   (kill old one first)');
console.log('');
console.log('Then watch the new tabs in the dashboard. Chatter starts during company office hours.');
console.log('');
